#!/usr/bin/env python3"""Test improved Jira search with better JQL queries"""import asyncioimport osimport jsonfrom dotenv import load_dotenvfrom autogen_ext.tools.mcp import StdioServerParams, McpWorkbenchload_dotenv()async def test_improved_search():    """Test various improved search approaches."""    def get_required_env(key: str) -> str:        value = os.getenv(key)        if not value:            raise RuntimeError(f"{key} environment variable not found")        return value    jira_server_params = StdioServerParams(        command="uvx",        args=["mcp-atlassian"],        env={            "JIRA_URL": get_required_env("JIRA_URL"),            "JIRA_USERNAME": get_required_env("JIRA_USERNAME"),            "JIRA_API_TOKEN": get_required_env("JIRA_API_TOKEN"),            "TOOLSETS": "all",        },        read_timeout_seconds=60,    )    async with McpWorkbench(jira_server_params) as jira:        print("🔗 Connected to Jira MCP server")        # Test various search strategies        search_queries = [            {                "name": "Basic project search",                "jql": "project = KAN",                "fields": "summary,status,priority,description,issuetype"            },            {                "name": "Project with issue type",                "jql": "project = KAN AND issuetype = Bug",                "fields": "summary,status,priority,description,issuetype"            },            {                "name": "Project with time range",                "jql": "project = KAN AND created >= -365d",                "fields": "summary,status,priority,description,created,issuetype"            },            {                "name": "Key range search",                "jql": "key >= KAN-1 AND key <= KAN-10",                "fields": "summary,status,priority,description,issuetype"            },            {                "name": "Specific KAN-5 search",                "jql": "key = KAN-5",                "fields": "summary,status,priority,description,issuetype"            }        ]        for query_info in search_queries:            print(f"\n🔍 {query_info['name']}")            print(f"   JQL: {query_info['jql']}")            try:                result = await jira.call_tool(                    "jira_search",                    {                        "jql": query_info["jql"],                        "fields": query_info["fields"],                        "limit": 10                    }                )                if hasattr(result, 'result') and result.result:                    data = json.loads(result.result[0].content)                    total = data.get('total', 0)                    issues = data.get('issues', [])                    print(f"   ✅ Found {total} total, showing {len(issues)} issues")                    for issue in issues:                        key = issue.get('key', 'Unknown')                        fields = issue.get('fields', {})                        summary = fields.get('summary', 'No summary')                        issue_type = fields.get('issuetype', {}).get('name', 'Unknown')                        status = fields.get('status', {}).get('name', 'Unknown')                        print(f"   🎫 {key}: {summary}")                        print(f"      Type: {issue_type}, Status: {status}")                        # If we have description, show first 100 chars                        description = fields.get('description')                        if description:                            desc_text = description if isinstance(description, str) else str(description)[:100]                            print(f"      Desc: {desc_text[:100]}...")                        print()                else:                    print(f"   ❌ No results: {result}")            except Exception as e:                print(f"   ❌ Error: {e}")if __name__ == "__main__":    asyncio.run(test_improved_search())